import{_ as e,o as l,c as d,a2 as a}from"./chunks/framework.Pywvta2k.js";const o=JSON.parse('{"title":"方剂速查索引","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/06-跨病证索引/05-方剂速查.md","filePath":"tcm-data/06-跨病证索引/05-方剂速查.md","lastUpdated":1781084559000}'),n={name:"tcm-data/06-跨病证索引/05-方剂速查.md"};function s(g,t,r,i,x,y){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="方剂速查索引" tabindex="-1">方剂速查索引 <a class="header-anchor" href="#方剂速查索引" aria-label="Permalink to &quot;方剂速查索引&quot;">​</a></h1><blockquote><p>按功能分类，跨医家 常用方以 ⭐ 标注</p></blockquote><hr><h2 id="一、补益类" tabindex="-1">一、补益类 <a class="header-anchor" href="#一、补益类" aria-label="Permalink to &quot;一、补益类&quot;">​</a></h2><h3 id="补气" tabindex="-1">补气 <a class="header-anchor" href="#补气" aria-label="Permalink to &quot;补气&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;">⭐ <strong>黄芽汤</strong></td><td style="text-align:left;">《四圣心源》</td><td style="text-align:left;">人参、甘草、茯苓、干姜</td><td style="text-align:left;">中气虚寒，土湿——<strong>基础方</strong></td></tr><tr><td style="text-align:left;"><strong>补中益气汤</strong></td><td style="text-align:left;">李东垣</td><td style="text-align:left;">黄芪、人参、白术、甘草、当归、陈皮、升麻、柴胡</td><td style="text-align:left;">脾胃气虚，少气懒言</td></tr><tr><td style="text-align:left;"><strong>四君子汤</strong></td><td style="text-align:left;">《局方》</td><td style="text-align:left;">人参、白术、茯苓、甘草</td><td style="text-align:left;">脾胃气虚基础方</td></tr><tr><td style="text-align:left;"><strong>玉屏风散</strong></td><td style="text-align:left;">朱震亨</td><td style="text-align:left;">黄芪、白术、防风</td><td style="text-align:left;">表虚自汗、反复感冒</td></tr><tr><td style="text-align:left;"><strong>黄芪建中汤</strong></td><td style="text-align:left;">《金匮》</td><td style="text-align:left;">小建中汤+黄芪</td><td style="text-align:left;">虚劳里急，诸不足</td></tr></tbody></table><h3 id="补血" tabindex="-1">补血 <a class="header-anchor" href="#补血" aria-label="Permalink to &quot;补血&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>四物汤</strong></td><td style="text-align:left;">《局方》</td><td style="text-align:left;">当归、川芎、芍药、地黄</td><td style="text-align:left;">血虚基础方</td></tr><tr><td style="text-align:left;">⭐ <strong>乌肝汤</strong></td><td style="text-align:left;">《四圣心源》</td><td style="text-align:left;">黄芽汤+附子、首乌、芍药、桂枝</td><td style="text-align:left;">肝血虚弱——<strong>参考方</strong></td></tr><tr><td style="text-align:left;"><strong>炙甘草汤</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">炙甘草、人参、生地、阿胶、麦冬、麻仁、桂枝、姜枣</td><td style="text-align:left;">脉结代、心动悸</td></tr></tbody></table><h3 id="补阴" tabindex="-1">补阴 <a class="header-anchor" href="#补阴" aria-label="Permalink to &quot;补阴&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>六味地黄丸</strong></td><td style="text-align:left;">钱乙</td><td style="text-align:left;">熟地、山萸、山药、泽泻、丹皮、茯苓</td><td style="text-align:left;">肾阴虚</td></tr><tr><td style="text-align:left;"><strong>大补阴丸</strong></td><td style="text-align:left;">朱震亨</td><td style="text-align:left;">熟地、龟板、黄柏、知母</td><td style="text-align:left;">阴虚火旺</td></tr><tr><td style="text-align:left;"><strong>左归丸</strong></td><td style="text-align:left;">张介宾</td><td style="text-align:left;">熟地、山药、枸杞、山萸、菟丝子、鹿角胶、龟板胶、牛膝</td><td style="text-align:left;">真阴不足</td></tr><tr><td style="text-align:left;">⭐ <strong>地魄汤</strong></td><td style="text-align:left;">《四圣心源》</td><td style="text-align:left;">甘草、半夏、麦冬、芍药、五味子、元参、牡蛎</td><td style="text-align:left;">肺胃阴虚，相火不降——<strong>参考方</strong></td></tr></tbody></table><h3 id="补阳" tabindex="-1">补阳 <a class="header-anchor" href="#补阳" aria-label="Permalink to &quot;补阳&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;">⭐ <strong>天魂汤</strong></td><td style="text-align:left;">《四圣心源》</td><td style="text-align:left;">黄芽汤+桂枝、附子</td><td style="text-align:left;">阳虚水寒——<strong>参考方</strong></td></tr><tr><td style="text-align:left;"><strong>右归丸</strong></td><td style="text-align:left;">张介宾</td><td style="text-align:left;">熟地、山药、山萸、枸杞、鹿角胶、菟丝子、杜仲、当归、肉桂、附子</td><td style="text-align:left;">命门火衰</td></tr><tr><td style="text-align:left;"><strong>八味肾气丸</strong></td><td style="text-align:left;">《金匮》</td><td style="text-align:left;">六味+桂枝、附子</td><td style="text-align:left;">肾阳虚</td></tr><tr><td style="text-align:left;"><strong>四逆汤</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">附子、干姜、甘草</td><td style="text-align:left;">少阴寒化，四肢厥逆</td></tr></tbody></table><hr><h2 id="二、和解类" tabindex="-1">二、和解类 <a class="header-anchor" href="#二、和解类" aria-label="Permalink to &quot;二、和解类&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>小柴胡汤</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">柴胡、黄芩、人参、半夏、甘草、生姜、大枣</td><td style="text-align:left;">少阳病，往来寒热</td></tr><tr><td style="text-align:left;"><strong>四逆散</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">柴胡、枳实、芍药、甘草</td><td style="text-align:left;">阳气郁遏，四肢不温</td></tr><tr><td style="text-align:left;"><strong>逍遥散</strong></td><td style="text-align:left;">《局方》</td><td style="text-align:left;">柴胡、当归、芍药、白术、茯苓、甘草</td><td style="text-align:left;">肝郁血虚</td></tr><tr><td style="text-align:left;">⭐ <strong>温胆汤</strong></td><td style="text-align:left;">《千金》</td><td style="text-align:left;">半夏、枳实、竹茹、陈皮、甘草、生姜</td><td style="text-align:left;">胆虚不眠——<strong>参考方</strong></td></tr></tbody></table><hr><h2 id="三、潜降安神类" tabindex="-1">三、潜降安神类 <a class="header-anchor" href="#三、潜降安神类" aria-label="Permalink to &quot;三、潜降安神类&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;">⭐ <strong>金鼎汤</strong></td><td style="text-align:left;">《四圣心源》</td><td style="text-align:left;">甘草、茯苓、半夏、桂枝、芍药、龙骨、牡蛎</td><td style="text-align:left;">相火不藏，惊悸——<strong>核心方</strong></td></tr><tr><td style="text-align:left;"><strong>桂枝甘草龙骨牡蛎汤</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">桂枝、甘草、龙骨、牡蛎</td><td style="text-align:left;">心悸烦躁</td></tr><tr><td style="text-align:left;"><strong>酸枣仁汤</strong></td><td style="text-align:left;">《金匮》</td><td style="text-align:left;">酸枣仁、甘草、知母、茯苓、川芎</td><td style="text-align:left;">虚烦不得眠</td></tr><tr><td style="text-align:left;"><strong>黄连阿胶汤</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">黄连、黄芩、芍药、阿胶、鸡子黄</td><td style="text-align:left;">少阴热化，心烦失眠</td></tr></tbody></table><hr><h2 id="四、温里祛寒类" tabindex="-1">四、温里祛寒类 <a class="header-anchor" href="#四、温里祛寒类" aria-label="Permalink to &quot;四、温里祛寒类&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>理中丸</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">人参、干姜、白术、甘草</td><td style="text-align:left;">太阴虚寒</td></tr><tr><td style="text-align:left;"><strong>小建中汤</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">桂枝汤+饴糖</td><td style="text-align:left;">虚劳里急</td></tr><tr><td style="text-align:left;"><strong>真武汤</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">附子、茯苓、白术、白芍、生姜</td><td style="text-align:left;">阳虚水泛</td></tr><tr><td style="text-align:left;"><strong>当归四逆汤</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">当归、桂枝、细辛、通草、甘草、大枣</td><td style="text-align:left;">手足厥寒</td></tr><tr><td style="text-align:left;">⭐ <strong>温氏奔豚汤</strong></td><td style="text-align:left;">李可</td><td style="text-align:left;">附子、油桂、红参、沉香、砂仁、山药、茯苓、泽泻、牛膝、甘草</td><td style="text-align:left;">上热下寒——<strong>参考方</strong></td></tr><tr><td style="text-align:left;"><strong>破格救心汤</strong></td><td style="text-align:left;">李可</td><td style="text-align:left;">附子30-200g、干姜、甘草、人参、山萸、龙牡磁</td><td style="text-align:left;">心衰、休克</td></tr></tbody></table><hr><h2 id="五、清热类" tabindex="-1">五、清热类 <a class="header-anchor" href="#五、清热类" aria-label="Permalink to &quot;五、清热类&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>白虎汤</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">石膏、知母、粳米、甘草</td><td style="text-align:left;">阳明经热</td></tr><tr><td style="text-align:left;"><strong>黄连解毒汤</strong></td><td style="text-align:left;">王焘</td><td style="text-align:left;">黄连、黄芩、黄柏、栀子</td><td style="text-align:left;">三焦火毒</td></tr><tr><td style="text-align:left;"><strong>普济消毒饮</strong></td><td style="text-align:left;">李东垣</td><td style="text-align:left;">黄芩、黄连、玄参、柴胡、桔梗、连翘等</td><td style="text-align:left;">大头瘟</td></tr><tr><td style="text-align:left;"><strong>导赤散</strong></td><td style="text-align:left;">钱乙</td><td style="text-align:left;">生地、木通、甘草、竹叶</td><td style="text-align:left;">心经火热</td></tr></tbody></table><hr><h2 id="六、祛湿化痰类" tabindex="-1">六、祛湿化痰类 <a class="header-anchor" href="#六、祛湿化痰类" aria-label="Permalink to &quot;六、祛湿化痰类&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>苓桂术甘汤</strong></td><td style="text-align:left;">《金匮》</td><td style="text-align:left;">茯苓、桂枝、白术、甘草</td><td style="text-align:left;">痰饮</td></tr><tr><td style="text-align:left;"><strong>二陈汤</strong></td><td style="text-align:left;">《局方》</td><td style="text-align:left;">半夏、陈皮、茯苓、甘草</td><td style="text-align:left;">湿痰</td></tr><tr><td style="text-align:left;"><strong>泽泻汤</strong></td><td style="text-align:left;">《金匮》</td><td style="text-align:left;">泽泻、白术</td><td style="text-align:left;">支饮眩冒</td></tr><tr><td style="text-align:left;"><strong>五苓散</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">猪苓、泽泻、白术、茯苓、桂枝</td><td style="text-align:left;">膀胱蓄水</td></tr></tbody></table><hr><h2 id="七、活血化瘀类" tabindex="-1">七、活血化瘀类 <a class="header-anchor" href="#七、活血化瘀类" aria-label="Permalink to &quot;七、活血化瘀类&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>桂枝茯苓丸</strong></td><td style="text-align:left;">《金匮》</td><td style="text-align:left;">桂枝、茯苓、丹皮、桃仁、芍药</td><td style="text-align:left;">瘀血内停</td></tr><tr><td style="text-align:left;"><strong>活络效灵丹</strong></td><td style="text-align:left;">张锡纯</td><td style="text-align:left;">当归、丹参、乳香、没药</td><td style="text-align:left;">瘀血痛</td></tr><tr><td style="text-align:left;"><strong>抵挡汤</strong></td><td style="text-align:left;">《伤寒论》</td><td style="text-align:left;">大黄、桃仁、水蛭、虻虫</td><td style="text-align:left;">蓄血重症</td></tr><tr><td style="text-align:left;"><strong>血府逐瘀汤</strong></td><td style="text-align:left;">王清任</td><td style="text-align:left;">桃红四物+四逆散</td><td style="text-align:left;">胸中瘀血</td></tr></tbody></table><hr><h2 id="八、妇科类-相关" tabindex="-1">八、妇科类（相关） <a class="header-anchor" href="#八、妇科类-相关" aria-label="Permalink to &quot;八、妇科类（相关）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">出处</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>温经汤</strong></td><td style="text-align:left;">《金匮》</td><td style="text-align:left;">吴萸、当归、川芎、芍药、人参、桂枝、阿胶、丹皮等</td><td style="text-align:left;">妇人少腹寒，月经不调</td></tr><tr><td style="text-align:left;"><strong>胶艾汤</strong></td><td style="text-align:left;">《金匮》</td><td style="text-align:left;">川芎、阿胶、甘草、艾叶、当归、芍药、生地</td><td style="text-align:left;">漏下</td></tr><tr><td style="text-align:left;"><strong>当归芍药散</strong></td><td style="text-align:left;">《金匮》</td><td style="text-align:left;">当归、芍药、川芎、茯苓、白术、泽泻</td><td style="text-align:left;">妇人腹中诸痛</td></tr><tr><td style="text-align:left;"><strong>完带汤</strong></td><td style="text-align:left;">傅青主</td><td style="text-align:left;">白术、山药、人参、白芍、车前子、苍术、甘草、陈皮、黑芥穗、柴胡</td><td style="text-align:left;">白带</td></tr><tr><td style="text-align:left;"><strong>清经散</strong></td><td style="text-align:left;">傅青主</td><td style="text-align:left;">丹皮、地骨皮、白芍、青蒿、黄柏、茯苓</td><td style="text-align:left;">月经先期血热</td></tr></tbody></table><hr><h2 id="参考方速查" tabindex="-1">参考方速查 <a class="header-anchor" href="#参考方速查" aria-label="Permalink to &quot;参考方速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">推荐方</th><th style="text-align:left;">核心药组</th></tr></thead><tbody><tr><td style="text-align:left;">⭐ <strong>整体调理</strong></td><td style="text-align:left;"><strong>温潜黄芽天魂汤</strong></td><td style="text-align:left;">参姜苓草+附桂+龙牡+归首乌+泽丹柏牛膝</td></tr><tr><td style="text-align:left;">中气虚寒</td><td style="text-align:left;">黄芽汤</td><td style="text-align:left;">人参、干姜、茯苓、甘草</td></tr><tr><td style="text-align:left;">相火不降</td><td style="text-align:left;">金鼎汤</td><td style="text-align:left;">龙骨、牡蛎、白芍</td></tr><tr><td style="text-align:left;">肝血不足</td><td style="text-align:left;">乌肝汤法</td><td style="text-align:left;">当归、首乌、桂枝</td></tr><tr><td style="text-align:left;">下焦湿热</td><td style="text-align:left;">四圣泄湿法</td><td style="text-align:left;">泽泻、黄柏、丹皮</td></tr><tr><td style="text-align:left;">血压高</td><td style="text-align:left;">上方潜降药组</td><td style="text-align:left;">龙骨、牡蛎、牛膝</td></tr></tbody></table><h2 id="参考方速查-1" tabindex="-1">参考方速查 <a class="header-anchor" href="#参考方速查-1" aria-label="Permalink to &quot;参考方速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">推荐方</th><th style="text-align:left;">核心药组</th></tr></thead><tbody><tr><td style="text-align:left;">⭐ <strong>整体调理</strong></td><td style="text-align:left;"><strong>加减黄芽地魄汤</strong></td><td style="text-align:left;">参姜苓草+当归芍药熟地+夏麦味+枣仁+牡蛎+柴胡+术+杜仲</td></tr><tr><td style="text-align:left;">中气虚</td><td style="text-align:left;">黄芽汤（减干姜）</td><td style="text-align:left;">人参、甘草、茯苓</td></tr><tr><td style="text-align:left;">相火浮越</td><td style="text-align:left;">地魄汤法</td><td style="text-align:left;">麦冬、五味子、牡蛎</td></tr><tr><td style="text-align:left;">肝郁血虚</td><td style="text-align:left;">四物去芎+柴胡</td><td style="text-align:left;">归芍地+柴胡</td></tr><tr><td style="text-align:left;">月经先期</td><td style="text-align:left;">固经养血</td><td style="text-align:left;">熟地、当归、白芍、杜仲</td></tr><tr><td style="text-align:left;">失眠</td><td style="text-align:left;">安神</td><td style="text-align:left;">酸枣仁、牡蛎</td></tr><tr><td style="text-align:left;">带多</td><td style="text-align:left;">健脾祛湿</td><td style="text-align:left;">白术、茯苓</td></tr></tbody></table><hr><p><em>本索引可随数据库扩展持续增加，如增加经方与时方的对比、患者（男）患者（女）专属方剂的细化等。</em></p>',40)])])}const h=e(n,[["render",s]]);export{o as __pageData,h as default};
